previewCss:
.darma-loader-uiverse-card-line-shimmer {
  display: inline-block;
  width: 104px;
  height: 14px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color) 12%, transparent), color-mix(in srgb, var(--loader-color) 35%, transparent), color-mix(in srgb, var(--loader-color) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-uiverse-card-line-shimmer-skeletonShimmer 1.05s linear infinite;
}
@keyframes darma-loader-uiverse-card-line-shimmer-skeletonShimmer { to { background-position: -220% 0; } }

